  svg.appendChild(t);
  if(d>0) svg.appendChild(SVG('line',{x1:m.l,y1:y,x2:W-m.r,y2:y,stroke:'var(--line)','stroke-dasharray':'2,3'}));
}
ks.forEach((k,i) => {
  const d = dimMk(k);
  const x = m.l + bw*i + bw*0.15;
  const y = yScale(d);
  const w = bw*0.7;
  const h = (H - m.b) - y;
  svg.appendChild(SVG('rect',{x,y,width:w,height:h,fill:'var(--yellow)',opacity:0.85,rx:2}));
  const tk = SVG('text',{x:x+w/2,y:H-m.b+18,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
  tk.textContent = 'k='+k;
  svg.appendChild(tk);
  if(d>0){
    const td = SVG('text',{x:x+w/2,y:y-4,'text-anchor':'middle','font-size':11,fill:'var(--ink)'});
    td.textContent = d;
    svg.appendChild(td);
  }
});
const t = SVG('text',{x:W-m.r,y:m.t+10,'text-anchor':'end','font-size':12,fill:'var(--mute)'});
t.textContent = 'dim M_k';
svg.appendChild(t);
out.textContent = 'Each bar is dim M_k. The Hecke algebra acts, and the space splits as an orthogonal sum of eigenspaces — each atom a single eigenform.';

const svg = document.getElementById('sub-svg');
const out = document.getElementById('sub-out');
const tauEl = document.getElementById('sub-tau');
if(!svg) return;
let p = 2;
const reEl = document.getElementById('sub-re');
const imEl = document.getElementById('sub-im');
document.querySelectorAll('.pbtn').forEach(b => {
  b.addEventListener('click', () => {
    document.querySelectorAll('.pbtn').forEach(x=>x.classList.remove('active'));
    b.classList.add('active');
    p = +b.dataset.p;
    draw();
  });
});
reEl.addEventListener('input', draw);
imEl.addEventListener('input', draw);

const W = 720, H = 320;
const cxMain = 160, cyMain = 160;
const scale = 46;  // pixels per lattice unit for the base lattice
function drawLattice(cx, cy, basis, opts={}){
  const {dotColor='var(--ink)', highlightDots=[], range=4, showBasis=true, basisColor='var(--yellow)', small=false} = opts;
  const sc = small ? 20 : scale;
  // draw faint grid of points
  for(let i=-range;i<=range;i++){
    for(let j=-range;j<=range;j++){
      const x = cx + sc*(i*basis.a + j*basis.c);
      const y = cy - sc*(i*basis.b + j*basis.d);
      if(x < cx-120 || x > cx+120 || y < cy-120 || y > cy+120) continue;
      const isHl = highlightDots.some(([ii,jj]) => ii===i && jj===j);
      svg.appendChild(SVG('circle',{cx:x,cy:y,r:isHl?3:1.8,
        fill:isHl?'var(--yellow)':dotColor,opacity:isHl?1:0.55}));
    }
  }
  if(showBasis){
    // basis vectors
    const e1x = cx + sc*basis.a, e1y = cy - sc*basis.b;
    const e2x = cx + sc*basis.c, e2y = cy - sc*basis.d;
    svg.appendChild(SVG('line',{x1:cx,y1:cy,x2:e1x,y2:e1y,stroke:basisColor,'stroke-width':1.6}));
    svg.appendChild(SVG('line',{x1:cx,y1:cy,x2:e2x,y2:e2y,stroke:basisColor,'stroke-width':1.6}));
  }
  svg.appendChild(SVG('circle',{cx,cy,r:2.5,fill:'var(--pink)'}));
}

function draw(){
  svg.innerHTML = '';
  const re = +reEl.value, im = +imEl.value;
  tauEl.textContent = `τ = ${re.toFixed(2)} + ${im.toFixed(2)}i`;

  // background
  svg.appendChild(SVG('rect',{x:0,y:0,width:W,height:H,fill:'var(--panel)'}));
  // divider
  svg.appendChild(SVG('line',{x1:300,y1:20,x2:300,y2:H-20,stroke:'var(--line)','stroke-dasharray':'3,4'}));

  // base lattice Λ = Z + Zτ
  // basis in (a + bi) complex form: ω1 = 1, ω2 = τ = re + im·i
  // we'll represent each as pixel vector: ω1 -> (scale, 0); ω2 -> (scale*re, -scale*im)
  const base = {a:1, b:0, c:re, d:im};
  // big label
  const hdr1 = SVG('text',{x:cxMain,y:30,'text-anchor':'middle','font-size':13,fill:'var(--ink)','font-weight':600});
  hdr1.textContent = 'Λ = ℤ + ℤτ';
  svg.appendChild(hdr1);
  drawLattice(cxMain, cyMain, base, {dotColor:'var(--ink)', showBasis:true, basisColor:'var(--blue)'});
  const l1 = SVG('text',{x:cxMain + scale + 8, y:cyMain+4,'font-size':11,fill:'var(--blue)'});
  l1.textContent = '1';
  svg.appendChild(l1);
  const l2 = SVG('text',{x:cxMain + scale*re + 8, y:cyMain - scale*im - 4,'font-size':11,fill:'var(--blue)'});
  l2.textContent = 'τ';
  svg.appendChild(l2);

  // right side: the p+1 sublattices as small diagrams
  const hdr2 = SVG('text',{x:510, y:30,'text-anchor':'middle','font-size':13,fill:'var(--ink)','font-weight':600});
  hdr2.textContent = `${p+1} sublattices of index ${p}`;
  svg.appendChild(hdr2);

  // arrange p+1 small lattices in a grid around (510, 160)
  const small_cx0 = 400, small_cy0 = 90;
  const cellW = 110, cellH = 110;
  const cols = Math.min(3, p+1);
  const rows = Math.ceil((p+1)/cols);
  // sublattice bases (column-wise in complex form):
  // Λ_∞: ω1' = p, ω2' = τ  => basis {a:p,b:0,c:re,d:im}, after scaling τ_new = τ/p (divide by p)
  //   but for showing the sublattice inside Λ, we use the lattice structure directly
  // Λ_b (b = 0..p-1): ω1' = 1 + b·τ, ω2' = p·τ  (scaled so ratio is (τ+b)/p after dividing by p)
  const lattices = [];
  lattices.push({label:'Λ_∞ (pτ)', basis:{a:p,b:0,c:re,d:im}, color:'var(--green)'});
  for(let b=0; b<p; b++){
    lattices.push({label:`Λ_${b} ((τ+${b})/p)`, basis:{a:1, b:0, c:b+p*re, d:p*im}, color:'var(--cyan)'});
    // note: using ω1' = 1, ω2' = p*τ + b  as vectors; above encodes that
  }
  // Actually better: use ω1' = p, ω2' = τ and ω1' = 1, ω2' = (τ+b) ... but for visualization
  // the sublattice is best shown as: points (m·ω1' + n·ω2') in Λ. Let's just emphasize the sub-lattice points.

  lattices.forEach((L, idx) => {
    const c = idx % cols;
    const r = Math.floor(idx/cols);
    const cx = small_cx0 + c*cellW + cellW/2;
    const cy = small_cy0 + r*cellH + cellH/2;
    // box
    svg.appendChild(SVG('rect',{x:cx-cellW/2+4, y:cy-cellH/2+4, width:cellW-8, height:cellH-8,
      fill:'var(--panel2)', stroke:L.color, 'stroke-width':1.2, rx:5}));
    // background Λ points (faint)
    const sc = 14;
    for(let i=-3;i<=3;i++){
      for(let j=-3;j<=3;j++){
        const x = cx + sc*(i + j*re);
        const y = cy - sc*(j*im);
        if(Math.abs(x-cx) < cellW/2-8 && Math.abs(y-cy) < cellH/2-10){
          svg.appendChild(SVG('circle',{cx:x,cy:y,r:1.2,fill:'var(--mute)',opacity:0.4}));
        }
      }
    }
    // sublattice points (highlighted)
    // for each sublattice, points = a·ω1' + b·ω2' in (x,y). We express ω1', ω2' in terms of (1,τ)
    let w1, w2;
    if(idx === 0){ w1 = {x:p, y:0}; w2 = {x:re, y:-im}; }
    else { const b = idx-1; w1 = {x:1, y:0}; w2 = {x:b + p*re, y:-p*im}; }
    for(let i=-3;i<=3;i++){
      for(let j=-2;j<=2;j++){
        const dx = sc*(i*w1.x + j*w2.x);
        const dy = sc*(i*w1.y + j*w2.y);
        const x = cx + dx, y = cy + dy;
        if(Math.abs(x-cx) < cellW/2-10 && Math.abs(y-cy) < cellH/2-14){
          svg.appendChild(SVG('circle',{cx:x,cy:y,r:2.4,fill:L.color,opacity:0.95}));
        }
      }
    }
    // label
    const t = SVG('text',{x:cx, y:cy+cellH/2-8,'text-anchor':'middle','font-size':10,fill:L.color});
    t.textContent = L.label;
    svg.appendChild(t);
  });

  out.textContent =
    `p = ${p}: (T_p f)(τ) = p^{k-1} f(pτ)  +  (1/p) · [ f(τ/p) + f((τ+1)/p) + ... + f((τ+${p-1})/p) ].` +
    `   Total: ${p+1} sublattices. The one marked Λ_∞ is p·ω_1 + ω_2, the others are ω_1 + b·ω_2 + p·ω_2 in the second direction.`;
}
draw();

