const svg = document.getElementById('qact-svg');
const out = document.getElementById('qact-out');
if(!svg) return;
const pSel = document.getElementById('qact-p');
const kSel = document.getElementById('qact-k');
const fSel = document.getElementById('qact-f');

// Ramanujan tau coefficients a_n of Δ, indexed by n=1..20
const tau = {1:1, 2:-24, 3:252, 4:-1472, 5:4830, 6:-6048, 7:-16744, 8:84480,
             9:-113643, 10:-115920, 11:534612, 12:-370944, 13:-577738, 14:401856,
             15:1217160, 16:987136, 17:-6905934, 18:2727432, 19:10661420, 20:-7109760};
// Eisenstein E_4 coefficients: E_4 = 1 + 240 Σ σ_3(n) q^n
function sigma3(n){ let s=0; for(let d=1; d<=n; d++) if(n%d===0) s += d*d*d; return s; }
function E4coeff(n){ return n===0 ? 1 : 240*sigma3(n); }

function draw(){
  svg.innerHTML='';
  const p = +pSel.value, k = +kSel.value, which = fSel.value;
  let a = {};
  let Nmax = 20;
  if(which === 'delta'){
    for(let n=1;n<=Nmax;n++) a[n] = tau[n] || 0;
    a[0] = 0;
  } else {
    for(let n=0;n<=Nmax;n++) a[n] = E4coeff(n);
  }
  const pkm1 = Math.pow(p, k-1);
  // compute c_n = a_{pn} + p^{k-1} a_{n/p}
  const c = {};
  for(let n=0; n<=Math.floor(Nmax/p); n++){
    const term1 = a[p*n] || 0;
    const term2 = (n%p===0) ? pkm1 * (a[n/p] || 0) : 0;
    c[n] = term1 + term2;
  }

  // layout: upper row = a_n, lower row = c_n
  const W = 720, H = 260, m = {l:50, r:20, t:30, b:30};
  const rows = 2;
  const rowH = (H - m.t - m.b) / rows;
  // normalize bars by log-scaling absolute value
  const vals = [];
  for(let n=0;n<=Nmax;n++) if(a[n]!==undefined) vals.push(Math.abs(a[n]));
  for(const k2 in c) vals.push(Math.abs(c[k2]));
  const vmax = Math.max(1, ...vals);
  function lh(v){ return v===0? 0 : (rowH*0.4) * Math.log(1+Math.abs(v)) / Math.log(1+vmax); }

  // upper: a_n
