const out = document.getElementById('mult-out');
if(!out) return;
// Extended tau: tau(n) for n=1..50 (via multiplicativity and Hecke recursion)
// We'll compute tau(n) up to 50 using tau(p) and tau(p^{r+1}) = tau(p) tau(p^r) - p^11 tau(p^{r-1})
const tauP = {2:-24, 3:252, 5:4830, 7:-16744, 11:534612, 13:-577738, 17:-6905934, 19:10661420,
              23:18643272, 29:128406630, 31:-52843168, 37:-182213314, 41:308120442, 43:-17125708, 47:2687348496};
const p11 = Math.pow(2, 11)*Math.pow(2,0); // 2^11 = 2048 is for p=2; we need p^11 per prime
function tauPrimePower(p, r){
  if(r === 0) return 1;
  if(r === 1) return tauP[p];
  let t_rm1 = 1, t_r = tauP[p];
  for(let i=1; i<r; i++){
    const nextVal = tauP[p]*t_r - Math.pow(p,11)*t_rm1;
    t_rm1 = t_r; t_r = nextVal;
  }
  return t_r;
}
function factor(n){
  const f = {};
  let x = n;
  for(let p=2; p*p<=x; p++){
    while(x%p===0){ f[p] = (f[p]||0)+1; x/=p; }
  }
  if(x>1) f[x] = (f[x]||0)+1;
  return f;
}
function tauN(n){
  if(n === 1) return 1;
  const f = factor(n);
  let prod = 1;
  for(const p in f){ prod *= tauPrimePower(+p, f[p]); }
  return prod;
}

