  const m = +mE.value, n = +nE.value;
  if(m<1 || n<1 || m>20 || n>20){ out.textContent = 'use 1 ≤ m,n ≤ 20'; return; }
  const am = tauN(m), an = tauN(n), amn = tauN(m*n);
  const g = gcd(m,n);
  const prod = am*an;
  let line1 = `τ(${m}) = ${am}\nτ(${n}) = ${an}\nτ(${m}·${n}) = τ(${m*n}) = ${amn}\n`;
  line1 += `τ(${m})·τ(${n}) = ${prod}\n`;
  if(g === 1){
    const ok = prod === amn;
    line1 += `gcd(${m},${n}) = 1, so we expect τ(m)τ(n) = τ(mn).  ${ok ? '✓ TRUE' : '✗ FALSE'}`;
