svg.appendChild(t1);
// cusp arrow
const ci = SVG('text',{x:cx,y:top+12,'text-anchor':'middle','font-size':11,fill:'var(--mute)','font-style':'italic'});
ci.textContent = 'cusp at i∞';
svg.appendChild(ci);

out.textContent =
