const svg = document.getElementById('eu-svg');
const out = document.getElementById('eu-out');
if(!svg) return;
const sel = document.getElementById('eu-p');
const taup = {2:-24, 3:252, 5:4830, 7:-16744, 11:534612, 13:-577738};

function draw(){
  svg.innerHTML='';
  const p = +sel.value;
  const ap = taup[p];
  const p11 = Math.pow(p,11);
  // roots α,β of 1 - a_p x + p^11 x^2 = 0  => x = (a_p ± √(a_p² - 4 p^11))/(2 p^11)
  // (inverse: solve p^11 x^2 - a_p x + 1 = 0)
  // actually: polynomial is 1 - a_p X + p^11 X^2; roots X = (a_p ± √(a_p² - 4 p^11)) / (2 p^11)
  const disc = ap*ap - 4*p11;
  let r1, r2, complex = false;
  if(disc >= 0){
    r1 = (ap + Math.sqrt(disc))/(2*p11);
    r2 = (ap - Math.sqrt(disc))/(2*p11);
  } else {
    complex = true;
    // X = (a_p ± i√(-disc)) / (2 p^11)
    r1 = {re: ap/(2*p11), im: Math.sqrt(-disc)/(2*p11)};
    r2 = {re: ap/(2*p11), im: -Math.sqrt(-disc)/(2*p11)};
  }
  // By Deligne, |X| = 1/p^{11/2}  (X is 1/α where α has |α| = p^{11/2})
  // Expected |X| = p^{-11/2}
  const absX = complex ? Math.sqrt(r1.re*r1.re + r1.im*r1.im) : Math.abs(r1);
  const expected = Math.pow(p, -11/2);

  // Plot: draw the Euler factor curve for real s in [0, 15]
  const W=720, H=200, m={l:60,r:30,t:20,b:30};
  const sMin=0, sMax=15;
  const xOf = s => m.l + (s-sMin)/(sMax-sMin)*(W-m.l-m.r);
  const f = s => 1 - ap*Math.pow(p,-s) + p11*Math.pow(p,-2*s);
  // sample
  const pts = [];
  for(let s=sMin; s<=sMax; s+=0.04){ pts.push([s, f(s)]); }
  const ys = pts.map(([_,v])=>v);
  const ymin = Math.min(...ys), ymax = Math.max(...ys);
  const yRange = Math.max(1e-9, ymax - ymin);
  const yOf = v => m.t + (ymax - v)/yRange * (H - m.t - m.b);
  // zero line
  const zeroY = yOf(0);
  if(zeroY >= m.t && zeroY <= H-m.b){
    svg.appendChild(SVG('line',{x1:m.l,y1:zeroY,x2:W-m.r,y2:zeroY,stroke:'var(--line)','stroke-dasharray':'3,4'}));
  }
  // axes
  svg.appendChild(SVG('line',{x1:m.l,y1:H-m.b,x2:W-m.r,y2:H-m.b,stroke:'var(--line)'}));
  svg.appendChild(SVG('line',{x1:m.l,y1:m.t,x2:m.l,y2:H-m.b,stroke:'var(--line)'}));
  // curve
  const pathD = pts.map(([s,v],i) => (i===0?'M':'L') + xOf(s) + ' ' + yOf(v)).join(' ');
  svg.appendChild(SVG('path',{d:pathD,fill:'none',stroke:'var(--yellow)','stroke-width':1.6}));
  // s ticks
  [0,3,6,9,12,15].forEach(s => {
    const x = xOf(s);
    svg.appendChild(SVG('line',{x1:x,y1:H-m.b,x2:x,y2:H-m.b+4,stroke:'var(--line)'}));
    const t = SVG('text',{x,y:H-m.b+18,'text-anchor':'middle','font-size':10,fill:'var(--mute)'});
    t.textContent = 's='+s;
    svg.appendChild(t);
  });
  const lab = SVG('text',{x:W-m.r-4,y:m.t+12,'text-anchor':'end','font-size':12,fill:'var(--yellow)'});
  lab.textContent = `L_p(Δ,s) = 1 − ${ap}·${p}^{−s} + ${p11}·${p}^{−2s}`;
  svg.appendChild(lab);

  out.textContent =
    `p = ${p}: a_p = τ(p) = ${ap}.  Euler factor 1 − a_p·p^{−s} + p^{11}·p^{−2s}.\n` +
    `Discriminant a_p² − 4·p^{11} = ${ap*ap} − ${4*p11} = ${ap*ap - 4*p11} ${disc < 0 ? '< 0 (complex roots — consistent with Ramanujan)' : '≥ 0'}\n` +
    `|root| = ${absX.toFixed(6)}, expected 1/p^{11/2} = ${expected.toFixed(6)} ${Math.abs(absX-expected)<1e-6 ? '✓' : ''}\n` +
    `So the inverse roots α_p, β_p of the polynomial X² − a_p X + p^{11} satisfy |α_p| = |β_p| = p^{11/2}, the Ramanujan–Deligne bound.`;
}
sel.addEventListener('change', draw);
draw();

